return await (async function(eda) {
  const fixtureName = '__codex_example___SCH_PrimitiveCircle_modify_' + Date.now();
  const currentProject = await eda.dmt_Project.getCurrentProjectInfo();
  if (!currentProject) { throw new Error('当前没有打开工程，先补齐环境再调试这个案例。'); }
  const currentDocument = await eda.dmt_SelectControl.getCurrentDocumentInfo();
  if (!currentDocument) {
    throw new Error('当前没有活动文档，先打开一个可操作的文档页。');
  }
  if (currentDocument.documentType !== 1) {
    throw new Error('当前文档类型不是 SCHEMATIC_PAGE，请先切到 原理图图页 再运行这个案例。');
  }
  const createdPrimitive = await eda.sch_PrimitiveCircle.create(
    120,
    80,
    30,
  );
  const primitiveId = createdPrimitive?.getState_PrimitiveId?.() ?? createdPrimitive?.primitiveId ?? createdPrimitive?.id;
  if (!primitiveId) { throw new Error('没有创建出可用于修改的测试图元。'); }
  const property = {
    radius: 40,
  };
  try {
    const before = await eda.sch_PrimitiveCircle.get(primitiveId);
    const result = await eda.sch_PrimitiveCircle.modify(primitiveId, property);
    const after = await eda.sch_PrimitiveCircle.get(primitiveId);
    return {
      fixtureName,
      primitiveId,
      property,
      before,
      result,
      after,
      cleanupStrategy: 'auto',
    };
  } finally {
    if (primitiveId) { await eda.sch_PrimitiveCircle.delete([primitiveId]); }
  }
})(eda);
